"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import { getNextStep } from "@/content";
import {
  triggerShake,
  getRandomComplete,
  getRandomEncourage,
} from "@/lib/learningMessages";

// ===== 重要日期定义 =====
// 每个日期对应一个月份，用户需要把它放到时间轴的正确月份位置
const DATES = [
  { id: "tree", icon: "🌸", label: "植树节", date: "3月12日", month: 3, color: "var(--accent3)" },
  { id: "children", icon: "🎈", label: "儿童节", date: "6月1日", month: 6, color: "var(--accent)" },
  { id: "national", icon: "🎉", label: "国庆节", date: "10月1日", month: 10, color: "var(--primary)" },
  { id: "christmas", icon: "🎄", label: "圣诞节", date: "12月25日", month: 12, color: "var(--accent2)" },
] as const;

const MONTHS = Array.from({ length: 12 }, (_, i) => i + 1);

// SVG 布局常量
const SEG = 100; // 每个月份段宽度（viewBox 单位）
const VB_W = 1200; // viewBox 宽度 = 12 * 100
const LINE_Y = 85; // 时间轴主线 y 坐标
const DOT_R = 11; // 圆点半径

/** 某个月份在时间轴上的中心 x 坐标 */
function monthCenterX(month: number): number {
  return (month - 0.5) * SEG;
}

type Feedback = { type: "ok" | "warn" | "hint"; text: string } | null;

export default function DrawPage() {
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [placed, setPlaced] = useState<Record<string, boolean>>({});
  const [hoveredMonth, setHoveredMonth] = useState<number | null>(null);
  const [feedback, setFeedback] = useState<Feedback>(null);
  const [completeMsg, setCompleteMsg] = useState("");
  useEffect(() => { setCompleteMsg(getRandomComplete()); }, []);

  const placedCount = DATES.filter((d) => placed[d.id]).length;
  const allDone = placedCount === DATES.length;
  const nextStep = getNextStep("calendar", "draw");

  const showFeedback = (fb: NonNullable<Feedback>, ms = 1800) => {
    setFeedback(fb);
    window.setTimeout(() => setFeedback(null), ms);
  };

  const handleCardClick = (id: string) => {
    if (placed[id]) return;
    setSelectedId(id);
    setFeedback(null);
  };

  const handleMonthClick = (month: number) => {
    if (allDone) return;
    if (!selectedId) {
      showFeedback({ type: "hint", text: "👆 先选一个日期卡片，再点时间轴哦" });
      return;
    }
    const date = DATES.find((d) => d.id === selectedId);
    if (!date || placed[date.id]) return;

    if (date.month === month) {
      // 放对了
      setPlaced((prev) => ({ ...prev, [date.id]: true }));
      setSelectedId(null);
      showFeedback({ type: "ok", text: `✓ ${date.label}在${date.month}月` });
    } else {
      // 放错了：抖动该日期卡片
      const cardEl = document.getElementById(`date-card-${date.id}`);
      triggerShake(cardEl);
      showFeedback({ type: "warn", text: getRandomEncourage() });
    }
  };

  const feedbackColor =
    feedback?.type === "ok"
      ? "bg-[var(--signal-success)]/15 text-[var(--signal-success)]"
      : feedback?.type === "warn"
      ? "bg-[var(--signal-shake)]/15 text-[var(--signal-shake)]"
      : "bg-[var(--bg-soft)] text-[var(--text-secondary)]";

  return (
    <StepShell topicId="calendar" stepId="draw">
      {/* 情境说明 */}
      <div className="mb-5 rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-soft)] p-4 text-center">
        <p className="text-[var(--text)]">📅 把重要日期标到时间轴的正确位置</p>
        <p className="mt-1 text-sm text-[var(--text-secondary)]">
          先点一个日期卡片，再点时间轴上对应的月份
        </p>
      </div>

      {/* 进度 + 反馈 */}
      <div className="mb-4 flex min-h-[28px] items-center justify-between gap-3">
        <span className="text-sm text-[var(--text-secondary)]">
          已标出 <strong className="text-[var(--accent-dark)]">{placedCount}</strong> / {DATES.length}
        </span>
        {feedback && (
          <span
            className={`rounded-full px-4 py-1 text-sm font-medium animate-float-in ${feedbackColor}`}
          >
            {feedback.text}
          </span>
        )}
      </div>

      {/* 时间轴 */}
      <div className="rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-4 shadow-[var(--shadow-sm)]">
        <svg
          viewBox={`0 0 ${VB_W} 150`}
          style={{ width: "100%", height: "auto", display: "block" }}
          role="img"
          aria-label="1月到12月的时间轴"
        >
          {/* 月份可点击区域（底层，接收所有点击） */}
          {MONTHS.map((m) => {
            const isHover = hoveredMonth === m;
            return (
              <rect
                key={`hit-${m}`}
                x={(m - 1) * SEG}
                y={15}
                width={SEG}
                height={120}
                style={{
                  fill: isHover ? "var(--bg-soft)" : "transparent",
                  cursor: selectedId && !allDone ? "pointer" : "default",
                }}
                onClick={() => handleMonthClick(m)}
                onMouseEnter={() => setHoveredMonth(m)}
                onMouseLeave={() => setHoveredMonth(null)}
              />
            );
          })}

          {/* 装饰层（不接收点击事件） */}
          <g style={{ pointerEvents: "none" }}>
            {/* 主线 */}
            <line
              x1={0}
              y1={LINE_Y}
              x2={VB_W}
              y2={LINE_Y}
              style={{ stroke: "var(--primary-light)", strokeWidth: 6, strokeLinecap: "round" }}
            />

            {/* 月份分隔刻度 */}
            {MONTHS.map((m) => (
              <line
                key={`tick-${m}`}
                x1={(m - 1) * SEG}
                y1={LINE_Y - 9}
                x2={(m - 1) * SEG}
                y2={LINE_Y + 9}
                style={{ stroke: "var(--border)", strokeWidth: 2 }}
              />
            ))}
            <line
              x1={VB_W}
              y1={LINE_Y - 9}
              x2={VB_W}
              y2={LINE_Y + 9}
              style={{ stroke: "var(--border)", strokeWidth: 2 }}
            />

            {/* 月份标签 */}
            {MONTHS.map((m) => (
              <text
                key={`label-${m}`}
                x={monthCenterX(m)}
                y={128}
                textAnchor="middle"
                style={{
                  fontSize: 15,
                  fill: hoveredMonth === m ? "var(--primary-dark)" : "var(--text-muted)",
                  fontWeight: hoveredMonth === m ? 700 : 500,
                }}
              >
                {m}月
              </text>
            ))}

            {/* 悬停提示手指 */}
            {selectedId && !allDone && hoveredMonth && (
              <text x={monthCenterX(hoveredMonth)} y={LINE_Y - 20} textAnchor="middle" style={{ fontSize: 18 }}>
                👆
              </text>
            )}

            {/* 已放置的日期：emoji + 日期 + 圆点 */}
            {DATES.filter((d) => placed[d.id]).map((d) => {
              const cx = monthCenterX(d.month);
              return (
                <g key={`placed-${d.id}`}>
                  <text x={cx} y={40} textAnchor="middle" style={{ fontSize: 24 }}>
                    {d.icon}
                  </text>
                  <text
                    x={cx}
                    y={62}
                    textAnchor="middle"
                    style={{ fontSize: 13, fill: "var(--text)", fontWeight: 700 }}
                  >
                    {d.date}
                  </text>
                  <circle
                    cx={cx}
                    cy={LINE_Y}
                    r={DOT_R}
                    style={{ fill: d.color, stroke: "white", strokeWidth: 3 }}
                  />
                </g>
              );
            })}
          </g>
        </svg>
      </div>

      {/* 日期卡片 */}
      <div className="mt-5 grid grid-cols-2 gap-3 sm:grid-cols-4">
        {DATES.map((d) => {
          const isPlaced = placed[d.id];
          const isSelected = selectedId === d.id;
          return (
            <button
              key={d.id}
              id={`date-card-${d.id}`}
              onClick={() => handleCardClick(d.id)}
              disabled={isPlaced}
              className={`overflow-hidden rounded-[var(--radius-sm)] border-2 text-center transition-all ${
                isPlaced
                  ? "border-[var(--signal-success)] bg-[var(--signal-success)]/10 opacity-70"
                  : isSelected
                  ? "scale-105 border-[var(--signal-focus)] bg-[var(--signal-focus)]/10 shadow-[var(--shadow-md)]"
                  : "border-[var(--border)] bg-[var(--bg-card)] hover:scale-105 hover:border-[var(--primary-light)]"
              }`}
            >
              {/* 顶部色条 */}
              <div
                style={{ height: 5, backgroundColor: isPlaced ? "var(--signal-success)" : d.color }}
              />
              <div className="p-3">
                <div className="text-2xl">{d.icon}</div>
                <div className="mt-1 text-sm font-bold text-[var(--text)]">{d.label}</div>
                <div className="text-xs text-[var(--text-secondary)]">{d.date}</div>
                {isPlaced && (
                  <div className="mt-1 text-xs font-semibold text-[var(--signal-success)]">
                    ✓ 已标出
                  </div>
                )}
                {isSelected && (
                  <div className="mt-1 text-xs font-semibold text-[var(--signal-focus)]">
                    已选中
                  </div>
                )}
              </div>
            </button>
          );
        })}
      </div>

      {/* 完成卡片 */}
      {allDone && (
        <div className="mt-6 rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-md)] animate-float-in">
          <div className="mb-2 text-4xl">🎉</div>
          <p className="text-lg font-semibold text-[var(--text)]">{completeMsg}</p>
          <p className="mt-2 text-sm text-[var(--text-secondary)]">
            你把 4 个重要日期都准确地标在了时间轴上！
          </p>
          {nextStep && (
            <Link
              href={nextStep.path}
              className="mt-6 inline-flex items-center gap-2 rounded-full bg-[var(--accent)] px-6 py-3 font-semibold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
            >
              下一步：{nextStep.label} →
            </Link>
          )}
        </div>
      )}
    </StepShell>
  );
}
